-- {"operators": "INNER_JOIN,AGGREGATE,UNION", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "CUSTOMER,OORDER,ORDER_LINE,HISTORY", "ducklake": true}
SELECT C_W_ID AS wid, SUM(OL_AMOUNT) AS amount, 'order' AS source FROM dl.CUSTOMER c JOIN dl.OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID JOIN dl.ORDER_LINE ol ON o.O_W_ID = ol.OL_W_ID AND o.O_D_ID = ol.OL_D_ID AND o.O_ID = ol.OL_O_ID GROUP BY C_W_ID UNION ALL SELECT H_C_W_ID AS wid, SUM(H_AMOUNT) AS amount, 'payment' AS source FROM dl.HISTORY GROUP BY H_C_W_ID;
